// ─── 导出函数 ────────────────────────────────────────────────

export function getCET4WordList(): string[] {
  const fromEnriched = ENRICHED.map(e => e.word);
  const fromCompact = COMPACT.map(c => c[0]);
  return [...new Set([...fromEnriched, ...fromCompact])];
}

export function getCET4WordCount(): number {
  return getCET4WordList().length;
}

export function lookupCET4Word(word: string): WordEntry | null {
  const enriched = ENRICHED.find(w => w.word === word);
  if (enriched) return enriched;
  const compact = COMPACT.find(c => c[0] === word);
  if (compact) {
    return {
      word: compact[0],
      phonetic: compact[1],
      meaning: compact[2],
      example: compact[3],
      exampleZh: compact[4],
      pos: compact[5],
      synonyms: [],
      antonyms: [],
      phrases: [],
      similarWords: [],
    };
  }
  return null;
}

export { ENRICHED, COMPACT };
